import { useState, useEffect } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/GestionarSalas.css";
import "../styles/RecursosModal.css";

const API_URL = "http://localhost:3001/api";

function GestionarSalas({ user }) {
  const [salas, setSalas] = useState([]);

  const [showModal, setShowModal] = useState(false);
  const [showInfoModal, setShowInfoModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);

  // 🔥 NUEVO MODAL RECURSOS
  const [showRecursosModal, setShowRecursosModal] = useState(false);

  const [selectedSala, setSelectedSala] = useState(null);

  const [editTab, setEditTab] = useState("info");

  const [editForm, setEditForm] = useState({
    nombre: "",
    ubicacion: "",
    capacidad: ""
  });

  const [editEstado, setEditEstado] = useState("");

  // 🔥 RECURSOS
  const [recursos, setRecursos] = useState([]);
  const [recursoSeleccionado, setRecursoSeleccionado] = useState(null);

  const [formRecurso, setFormRecurso] = useState({
    codigo: "",
    tipo: "",
    descripcion: ""
  });

  const [tabRecurso, setTabRecurso] = useState("ver");

  const [sala, setSala] = useState({
    id: "",
    nombre: "",
    ubicacion: "",
    capacidad: ""
  });

  const obtenerSalas = async () => {
    const res = await fetch(`${API_URL}/salas`, {
      credentials: "include"
    });
    const data = await res.json();
    setSalas(data);
  };

  const obtenerRecursos = async (idSala) => {
    const res = await fetch(`${API_URL}/sala-recursos/sala/${idSala}`, {
      credentials: "include"
    });
    const data = await res.json();
    setRecursos(data);
  };

  useEffect(() => {
    obtenerSalas();
  }, []);

  const crearSala = async () => {
    await fetch(`${API_URL}/salas`, {
      method: "POST",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...sala,
        capacidad: Number(sala.capacidad),
        estado: "disponible"
      })
    });

    setShowModal(false);
    obtenerSalas();
  };

  const editarInfo = async () => {
    await fetch(`${API_URL}/salas/${selectedSala.id}/datos`, {
      method: "PUT",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ...editForm,
        capacidad: Number(editForm.capacidad)
      })
    });

    obtenerSalas();
  };

  const editarEstado = async () => {
    await fetch(`${API_URL}/salas/${selectedSala.id}`, {
      method: "PUT",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        estado: editEstado
      })
    });

    obtenerSalas();
  };

  // 🔥 AGREGAR RECURSO
  const agregarRecurso = async () => {
    await fetch(`${API_URL}/sala-recursos`, {
      method: "POST",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id_sala: selectedSala.id,
        ...formRecurso
      })
    });

    obtenerRecursos(selectedSala.id);

    setFormRecurso({
      codigo: "",
      tipo: "",
      descripcion: ""
    });
  };

  // 🔥 ELIMINAR RECURSO
  const eliminarRecurso = async () => {
    await fetch(`${API_URL}/sala-recursos`, {
      method: "DELETE",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        id_sala: selectedSala.id,
        id_recurso: recursoSeleccionado.id_recurso
      })
    });

    setRecursoSeleccionado(null);
    obtenerRecursos(selectedSala.id);
  };

  return (
    <div className="container">
      <NavbarGestionSalas userRole={user?.rol || ""} />

      <div className="header">
        <h2>Gestión de Salas</h2>
        <button className="btn-crear" onClick={() => setShowModal(true)}>
          + Crear Sala
        </button>
      </div>

      {/* GRID */}
      <div className="grid-salas">
        {salas.map((s) => (
          <div key={s.id} className="card">
            <div className="card-content">
              <h3>{s.nombre}</h3>
              <p>{s.ubicacion}</p>

              <div className="card-info">
                <span>👥 {s.capacidad}</span>
                <span className={`estado ${s.estado}`}>{s.estado}</span>
              </div>
            </div>

            <div className="overlay">
              <button onClick={() => {
                setSelectedSala(s);
                setShowInfoModal(true);
              }}>
                Ver Info
              </button>

              {/* 🔥 RECURSOS */}
              <button onClick={() => {
                setSelectedSala(s);
                setShowRecursosModal(true);
                obtenerRecursos(s.id);
              }}>
                Recursos
              </button>

              <button className="editar" onClick={() => {
                setSelectedSala(s);
                setShowEditModal(true);
                setEditForm({
                  nombre: s.nombre,
                  ubicacion: s.ubicacion,
                  capacidad: s.capacidad
                });
                setEditEstado(s.estado);
              }}>
                Editar
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* 🔥 MODAL RECURSOS */}
      {showRecursosModal && selectedSala && (
        <div className="modal-overlay">
          <div className="modal recursos-modal">

            <h3>Recursos - {selectedSala.nombre}</h3>

            <div className="tabs">
              <button
                className={tabRecurso === "ver" ? "active" : ""}
                onClick={() => setTabRecurso("ver")}
              >
                Recursos
              </button>

              <button
                className={tabRecurso === "agregar" ? "active" : ""}
                onClick={() => setTabRecurso("agregar")}
              >
                Agregar
              </button>
            </div>

            {/* VER */}
            {tabRecurso === "ver" && (
              <>
                <div className="lista-recursos-modal">
                  {recursos.map((r) => (
                    <div
                      key={r.id_recurso}
                      className={`recurso-card ${
                        recursoSeleccionado?.id_recurso === r.id_recurso ? "selected" : ""
                      }`}
                      onClick={() => setRecursoSeleccionado(r)}
                    >
                      <h4>{r.tipo}</h4>
                      <p>{r.descripcion}</p>
                      <span>{r.codigo}</span>
                    </div>
                  ))}
                </div>

                <button className="btn-eliminar" onClick={eliminarRecurso}>
                  Eliminar
                </button>
              </>
            )}

            {/* AGREGAR */}
            {tabRecurso === "agregar" && (
              <>
                <input placeholder="Código"
                  value={formRecurso.codigo}
                  onChange={e=>setFormRecurso({...formRecurso,codigo:e.target.value})}/>

                <input placeholder="Tipo"
                  value={formRecurso.tipo}
                  onChange={e=>setFormRecurso({...formRecurso,tipo:e.target.value})}/>

                <input placeholder="Descripción"
                  value={formRecurso.descripcion}
                  onChange={e=>setFormRecurso({...formRecurso,descripcion:e.target.value})}/>

                <button className="btn-agregar" onClick={agregarRecurso}>
                  Agregar
                </button>
              </>
            )}

            <button className="btn-cerrar" onClick={()=>setShowRecursosModal(false)}>
              Cerrar
            </button>

          </div>
        </div>
      )}

      <footer className="footer">
        <p>Sistema de Gestión de Salas © 2026</p>
      </footer>
    </div>
  );
}

export default GestionarSalas;
